patch:
@@ -2,9 +2,10 @@
 //  NewMaterialDialog.qml
 //  qml/hifi
 //
-//  Created by Sam Gondelman on 1/17/18
+//  Created by Sam Gondelman on January 17th, 2018
 //  Copyright 2018 High Fidelity, Inc.
